import { useEffect, useState } from "react";
import PageHeader from "../components/PageHeader";
import { getAdminUsers, updateUserBlockStatus } from "../services/api";

export default function AdminUsersPage() {
  const [users, setUsers] = useState([]);

  const load = async () => setUsers(await getAdminUsers());
  useEffect(() => { load(); }, []);

  const toggleBlock = async (user) => {
    await updateUserBlockStatus(user.id, !user.is_blocked);
    load();
  };

  return (
    <>
      <PageHeader title="User Management" description="Review patient profiles, symptoms, and status in a dedicated administration page." />
      <div className="panel">
        <div className="table-wrap">
          <table>
            <thead>
              <tr><th>Name</th><th>Age</th><th>Gender</th><th>Latest Symptom</th><th>Status</th><th>Action</th></tr>
            </thead>
            <tbody>
              {users.map((user) => (
                <tr key={user.id}>
                  <td>{user.name}</td>
                  <td>{user.age}</td>
                  <td>{user.gender}</td>
                  <td>{user.latest_symptom || "-"}</td>
                  <td><span className="pill">{user.status}</span></td>
                  <td><button className="btn btn-secondary" onClick={() => toggleBlock(user)}>{user.is_blocked ? "Unblock" : "Block"}</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </>
  );
}
